   useEffect(() => {
+    if (!showAgentStatus) return
+
+    const CLOSE_DISTANCE = 20
+
     const handleClickOutside = (event: MouseEvent) => {
       if (agentRef.current && !agentRef.current.contains(event.target as Node)) {
         setShowAgentStatus(false)
       }
     }
